head.script:
//-------------------------------------------------------------------------
// 호출페이지에서 보낸 파라미터 받기
//-------------------------------------------------------------------------
scwin.param = "";

scwin.odrNo           = "";
scwin.wageRsltsSeq    = "";
scwin.wrkPlCd         = "";
scwin.wrkDt           = "";
scwin.shiftClsCd      = "";
scwin.holdNo          = "";
scwin.commCd          = "";
scwin.wrkStpCd1       = "";
scwin.wrkStpCd2       = "";
scwin.wrkStpCd3       = "";
scwin.wrkStpCd4       = "";
scwin.wrkMthdCd      = "";
scwin.wrkQty	       = "";
scwin.wageVol        = "";
scwin.expimpClsCd    = "";
scwin.eqClssCd       = "";
scwin.wageGoodsCd    = "";
scwin.wageVolUnit   = ""; 

scwin.chk = 0;

//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    // 호출페이지에서 보낸 배열값 세팅(추후 연결)
    scwin.param = $p.getAllParameter().paramData.data;

    let i = 0;
    chk = 0;

    scwin.odrNo           = scwin.param[i++];
    scwin.wageRsltsSeq    = scwin.param[i++];
    scwin.wrkPlCd         = scwin.param[i++];
    scwin.wrkDt           = scwin.param[i++];
    scwin.shiftClsCd      = scwin.param[i++];
    scwin.holdNo          = scwin.param[i++];
    scwin.commCd          = scwin.param[i++];
    scwin.wrkStpCd1       = scwin.param[i++];
    scwin.wrkStpCd2       = scwin.param[i++];
    scwin.wrkStpCd3       = scwin.param[i++];
    scwin.wrkStpCd4       = scwin.param[i++];

    scwin.wrkMthdCd      = scwin.param[i++];
    scwin.wrkQty	     = scwin.param[i++];
    scwin.wageVol        = scwin.param[i++];
    scwin.expimpClsCd    = scwin.param[i++];
    scwin.eqClssCd       = scwin.param[i++];
    scwin.wageGoodsCd    = scwin.param[i++];
    scwin.wageVolUnit    = scwin.param[i++]; 


    //공통코드데이터 호출   
    const codeOptions = [
    { grpCd: "OP241", compID: "gr_retrieveResult:wrkMthdCd" }, // 셀렉트
    { grpCd: "SD060", compID: "gr_retrieveResult:expimpClsCd" }, // 셀렉트
    ];

    $c.data.setCommonCode(codeOptions);


    const param = [
         {
            method: "getGridCombo", 
            param1: "StevedoringWagesResultsEBC", 
            param2: "retriveHKindList",
            compID: "gr_retrieveResult:eqClssCd" 
        }
    ];
    $c.data.setGauceUtil(param);


    dma_condition.set("odrNo", scwin.odrNo);
    dma_condition.set("upperWageRsltsSeq", scwin.wageRsltsSeq );
    dma_condition.set("wrkPlCd", scwin.wrkPlCd);
    dma_condition.set("wrkDt", scwin.wrkDt);
    dma_condition.set("shiftClsCd", scwin.shiftClsCd  );
    dma_condition.set("holdNo", scwin.holdNo);
    dma_condition.set("commCd", scwin.commCd);
    dma_condition.set("wrkStpCd1", scwin.wrkStpCd1);
    dma_condition.set("wrkStpCd2", scwin.wrkStpCd2);
    dma_condition.set("wrkStpCd3", scwin.wrkStpCd3);
    dma_condition.set("wrkStpCd4", scwin.wrkStpCd4);
    dma_condition.set("wrkMthdCd", scwin.wrkMthdCd);
    dma_condition.set("wrkQty", scwin.wrkQty);
    dma_condition.set("wageVol", scwin.wageVol);
    dma_condition.set("expimpClsCd", scwin.expimpClsCd);
    dma_condition.set("eqClssCd", scwin.eqClssCd);
    dma_condition.set("wageGoodsCd", scwin.wageGoodsCd); 
    dma_condition.set("wageVolUnit", scwin.wageVolUnit); 



    // $c.sbm.execute(sbm_retrieve);
    scwin.f_Retrieve();
    //scwin.f_chkCheck(ds_retrieveResult.getTotalRow());
    scwin.popTitleCh();
};

scwin.popTitleCh = function() {
    $c.data.setPopupTitle("노임항목 상세요율");

}


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function() {
    $c.sbm.execute(sbm_retrieve);

}


//-------------------------------------------------------------------------
// 추가 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_add = function (e) {

    // 데이터리스트 필터
    ds_retrieveResult.clearFilter();

    let fn_tmpDeptFilter = function(cellData, tmpParam, rowIdx){
    if(ds_retrieveResult.getCellData(rowIdx, "chk") == "1" && ds_retrieveResult.getRowStatus(rowIdx) != "R"){
            return true;
        }else {
            return false;   // return이 true인 경우 적용하고 false인 경우 넘김
        }
    }   

    ds_retrieveResult.setColumnFilter( 
        {type:"func", colIndex:"chk", key:fn_tmpDeptFilter, condition:"and"}
    );

    let row = ds_retrieveResult.getRowCount(); // 필터된 경우에는 getTotalRow() 사용하면 안됨
    let result = new Array();
    let count = 0;

    for(let j = 0; j < row; j++){
        result[j] = new Array();
    }

    for(let i = 0; i < row; i++){
        if(ds_retrieveResult.getRowStatus(i) != "R"){
            result[i][count++] = ds_retrieveResult.getCellData(i,"districtCd"        );
            result[i][count++] = ds_retrieveResult.getCellData(i,"selpchItemCd"      );
            result[i][count++] = ds_retrieveResult.getCellData(i,"selpchItemNm"      );
            result[i][count++] = ds_retrieveResult.getCellData(i,"scDtlSeqNo"        );
            result[i][count++] = ds_retrieveResult.getCellData(i,"adptStDt"          );
            result[i][count++] = ds_retrieveResult.getCellData(i,"dtlItemNm"         );
            result[i][count++] = ds_retrieveResult.getCellData(i,"goodsCd"           );
            result[i][count++] = ds_retrieveResult.getCellData(i,"goodsNm"           );
            result[i][count++] = ds_retrieveResult.getCellData(i,"adptStdGoods"      );
            result[i][count++] = ds_retrieveResult.getCellData(i,"adptStdGoodsNm"    );
            result[i][count++] = ds_retrieveResult.getCellData(i,"eqClssCd"          );
            result[i][count++] = ds_retrieveResult.getCellData(i,"wtTenfrAdptSt"     );
            result[i][count++] = ds_retrieveResult.getCellData(i,"wtTenfrAdptEnd"    );
            result[i][count++] = ds_retrieveResult.getCellData(i,"expimpClsCd"       );
            result[i][count++] = ds_retrieveResult.getCellData(i,"wrkMthdCd"         );
            result[i][count++] = ds_retrieveResult.getCellData(i,"cvsslWharfPartyCnt");
            result[i][count++] = ds_retrieveResult.getCellData(i,"seaWrkYn"          );
            result[i][count++] = ds_retrieveResult.getCellData(i,"scWtAdptStd"       );
            result[i][count++] = ds_retrieveResult.getCellData(i,"adptTermSprtYn"    );
            result[i][count++] = ds_retrieveResult.getCellData(i,"adptTermStDt"      );
            result[i][count++] = ds_retrieveResult.getCellData(i,"adptTermEndDt"     );
            result[i][count++] = ds_retrieveResult.getCellData(i,"scAmt"             );
            result[i][count++] = ds_retrieveResult.getCellData(i,"scRt"              );
            result[i][count++] = ds_retrieveResult.getCellData(i,"adptEndDt"         );
            result[i][count++] = ds_retrieveResult.getCellData(i,"wageAgrmntDt"      );
            result[i][count++] = ds_retrieveResult.getCellData(i,"wrkPl"             );
            result[i][count++] = ds_retrieveResult.getCellData(i,"adptTonCnt"        );
        }
        count = 0;
    }

    $c.win.closePopup(result);
};


//-------------------------------------------------------------------------
// 그리드 셀 클릭시 넘어오는 메소드
//-------------------------------------------------------------------------
scwin.f_chkCheck = function(row, colid) {
    let rowCnt = ds_retrieveResult.getTotalRow();

    // if(row == "0" && colid == "column1"){
    //     scwin.f_allcheckbox();
    // }

    if(ds_retrieveResultCopy.getCellData(row, "chk") == 1) {
        ds_retrieveResult.setCellData(row, "chk", ds_retrieveResultCopy.getCellData(row, "chk"));
    }

    else{}
}

//-------------------------------------------------------------------------
// 전체 선택
//-------------------------------------------------------------------------
scwin.f_allcheckbox = function() {
    let rowCnt = ds_retrieveResult.getTotalRow();

    if(scwin.chk == 0)    {
        for (i=0; i < rowCnt; i++) {
            ds_retrieveResult.setCellData(i, "chk", "1");
        }
        scwin.chk = 1;
    }
    else if ( scwin.chk == 1 ) {
        for (i = 0; i < rowCnt; i++) {
            ds_retrieveResult.setCellData(i, "chk", ds_retrieveResultCopy.getCellData(i, "chk"));
        }
        scwin.chk = 0;
    }

}


//-------------------------------------------------------------------------
// 그리드 셀 클릭
//-------------------------------------------------------------------------
scwin.gr_retrieveREsult_onClick = function (rowIndex, columnIndex, columnId) {
    scwin.f_chkCheck(rowIndex, columnId);
};

//-------------------------------------------------------------------------
// 취소 클릭
//-------------------------------------------------------------------------
scwin.btn_close_onClick = function (e) {
    $c.win.closePopup();
};

//-------------------------------------------------------------------------
// 데이터 로드 완료시
//-------------------------------------------------------------------------
scwin.ds_retrieveResult_ondataload = function () {
    spa_totalRows.setValue(ds_retrieveResult.getTotalRow());
    gr_retrieveResult.setFocusedCell(0, 0);

    $c.gus.cfCopyDataSet(ds_retrieveResult, ds_retrieveResultCopy , "copyHeader=Yes");
};

scwin.gr_retrieveResult_onheaderclick = function (headerId) {
    if(headerId == "column1") {
        scwin.f_allcheckbox();
    }


};


scwin.sbm_retrieve_submitDone = function (e) {
    console.log("왔니");
};

scwin.sbm_retrieve_submitError = function (e) {

};
